    /// Average log10 bigram probability of `word` under the EN model.
    public static func scoreEn(_ word: String) -> Double {
        score(word.lowercased(), en, enFloor)
    }

    /// Average log10 bigram probability of `word` under the RU model.
    public static func scoreRu(_ word: String) -> Double {
        score(word.lowercased(), ru, ruFloor)
    }

    /// Average log10 bigram probability of `word` under the UK model.
    public static func scoreUk(_ word: String) -> Double {
        score(word.lowercased(), uk, ukFloor)
    }

    private static func score(_ w: String, _ model: [String: Double], _ floor: Double) -> Double {
        let a = Array(w)
        if a.count < 2 { return floor }
        var sum = 0.0
        for i in 0..<(a.count - 1) {
            let bg = String(a[i...(i + 1)])
            sum += model[bg] ?? floor
        }
        return sum / Double(a.count - 1)
    }

    private static func parse(_ packed: String) -> [String: Double] {
        var d = [String: Double]()
        for tok in packed.split(separator: " ") {
            guard let c = tok.lastIndex(of: ":") else { continue }
            let key = String(tok[tok.startIndex..<c])
            let val = Double(tok[tok.index(after: c)...]) ?? 0
            d[key] = val
        }
        return d
    }
}
